    // Precompute the popcount-depth for numbers up to 64 bits
    // Since k is at most 5, we can use BFS to find numbers with popcount-depth exactly k
    // We use BFS to simulate the sequence and track the depth

    // Function to calculate popcount (number of 1s in binary representation)
    function popcount(x: number): number {
        let count = 0;
        while (x) {
            x &= x - 1; // Clear the least significant 1
            count++;
        }
        return count;
    }

    // BFS to find numbers with popcount-depth exactly k
    // We use a queue to process numbers and track their depth
    // We also use a set to avoid revisiting numbers
    const queue: number[] = [];
    const visited: Set<number> = new Set();
    const result: Map<number, number> = new Map();

    // Start with all numbers from 1 to 64 (since numbers larger than 64 will have popcount-depth 1)
    for (let i = 1; i <= 64; i++) {
        queue.push(i);
        visited.add(i);
    }

    // BFS processing
