        const current = queue.shift()!;
        const currentDepth = result.get(current) || 0;

        // If current depth is already known, skip
        if (currentDepth !== 0) {
            continue;
        }

        // If current number is 1, its depth is 1
        if (current === 1) {
            result.set(current, 1);
            continue;
        }

        // Calculate the next number in the sequence
        const next = popcount(current);

        // If next is 1, the depth is currentDepth + 1
        if (next === 1) {
            result.set(current, currentDepth + 1);
        } else {
            // If next hasn't been processed yet, add it to the queue
            if (!visited.has(next)) {
                visited.add(next);
                queue.push(next);
            }
        }
    }

    // Count numbers in [1, n] with popcount-depth exactly k
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (result.has(i) && result.get(i) === k) {
            count++;
        }
    }

    return count;
}

